{
  "type": "object",
  "properties": {
    "date": {
      "type": "string",
      "description": "Date to check in YYYY-MM-DD format, e.g. 2025-03-20"
    },
    "time": {
      "type": "string",
      "description": "Start time in HH:MM 24h format, e.g. 14:30"
    },
    "duration_minutes": {
      "type": "number",
      "description": "Duration of the appointment in minutes: 45 for Haircut, 90 for Coloring, 60 for Hair Care, 120 for Combo"
    }
  },
  "required": ["date", "time", "duration_minutes"]
}

parameters.jsCode:
// Parse input - the AI passes a JSON string as 'query'
let input;
try {
  input = typeof query === 'string' ? JSON.parse(query) : query;
} catch (e) {
  return `Error: Invalid input format. Expected JSON with date, time, and duration_minutes. Got: ${query}`;
}

const { date, time, duration_minutes } = input;

if (!date || !time || !duration_minutes) {
  return 'Error: Missing required fields. Please provide date (YYYY-MM-DD), time (HH:MM), and duration_minutes.';
}

// Validate date format
const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
if (!dateRegex.test(date)) {
  return `Error: Invalid date format '${date}'. Use YYYY-MM-DD.`;
}

// Validate time format
const timeRegex = /^\d{2}:\d{2}$/;
if (!timeRegex.test(time)) {
  return `Error: Invalid time format '${time}'. Use HH:MM (24h).`;
}

// Check day of week (use noon to avoid DST issues)
const checkDate = new Date(date + 'T12:00:00');
const dayOfWeek = checkDate.getDay(); // 0=Sunday, 6=Saturday

if (dayOfWeek === 0) {
  return `NOT AVAILABLE: The salon is closed on Sundays. Please choose a Monday through Saturday date.`;
}

// Check working hours
const [hours, minutes] = time.split(':').map(Number);
const startMin = hours * 60 + minutes;
const endMin = startMin + Number(duration_minutes);
const openMin = 9 * 60;   // 9:00
const closeMin = 20 * 60; // 20:00

if (startMin < openMin || endMin > closeMin) {
  const endH = Math.floor(endMin / 60).toString().padStart(2, '0');
  const endM = (endMin % 60).toString().padStart(2, '0');
  return `NOT AVAILABLE: The time ${time} with ${duration_minutes}-minute duration is outside working hours (09:00-20:00). The appointment would end at ${endH}:${endM}. Please choose an earlier time.`;
}

// Calculate end time string
const endH = Math.floor(endMin / 60).toString().padStart(2, '0');
const endM = (endMin % 60).toString().padStart(2, '0');
const endTime = `${endH}:${endM}`;

// Saturday special handling
if (dayOfWeek === 6) {
  const calId = typeof $env !== 'undefined' ? ($env.GOOGLE_CALENDAR_ID || 'primary') : 'primary';
  const token = typeof $env !== 'undefined' ? ($env.GOOGLE_CALENDAR_ACCESS_TOKEN || '') : '';

  try {
    const resp = await $helpers.httpRequest({
      method: 'GET',
      url: `https://www.googleapis.com/calendar/v3/calendars/${encodeURIComponent(calId)}/events`,
      headers: { 'Authorization': `Bearer ${token}` },
      qs: {
        timeMin: `${date}T${time}:00-03:00`,
        timeMax: `${date}T${endTime}:00-03:00`,
        singleEvents: true,
        orderBy: 'startTime'
      }
    });
    const busy = (resp.items || []).filter(e => e.status !== 'cancelled');
    if (busy.length === 0) {
      return `AVAILABLE (Saturday - special appointment): The slot ${date} at ${time}-${endTime} appears free. Note: Saturday bookings require confirmation from Master Artem.`;
    } else {
      return `NOT AVAILABLE: The slot ${date} at ${time} is already booked.`;
    }
  } catch (err) {
    return `AVAILABLE (Saturday - unverified): Calendar check failed (${err.message}). The working hours are valid for ${date} at ${time}-${endTime}. Saturday requires special confirmation from Master Artem.`;
  }
}

// Weekday: query Google Calendar
const calId = typeof $env !== 'undefined' ? ($env.GOOGLE_CALENDAR_ID || 'primary') : 'primary';
const token = typeof $env !== 'undefined' ? ($env.GOOGLE_CALENDAR_ACCESS_TOKEN || '') : '';

try {
  const resp = await $helpers.httpRequest({
    method: 'GET',
    url: `https://www.googleapis.com/calendar/v3/calendars/${encodeURIComponent(calId)}/events`,
    headers: { 'Authorization': `Bearer ${token}` },
    qs: {
      timeMin: `${date}T${time}:00-03:00`,
      timeMax: `${date}T${endTime}:00-03:00`,
      singleEvents: true,
      orderBy: 'startTime'
    }
  });

  const busy = (resp.items || []).filter(e => e.status !== 'cancelled');

  if (busy.length === 0) {
    return `AVAILABLE: The slot on ${date} from ${time} to ${endTime} (${duration_minutes} min) is free. You can proceed with booking.`;
  } else {
    const list = busy.map(e => {
      const s = e.start.dateTime ? e.start.dateTime.substring(11, 16) : e.start.date;
      const en = e.end.dateTime ? e.end.dateTime.substring(11, 16) : e.end.date;
      return `${s}-${en}: ${e.summary || 'Appointment'}`;
    }).join('; ');
    return `NOT AVAILABLE: The slot ${date} at ${time} conflicts with existing appointment(s): ${list}. Please suggest another time to the client.`;
  }
} catch (err) {
  // Fallback: hours check passed, calendar unavailable
  return `AVAILABLE (unverified - calendar API error: ${err.message}): Working hours check passed for ${date} at ${time}-${endTime}. Proceed with booking but verify manually for conflicts.`;
}

