// Parse input
let input;
try {
  input = typeof query === 'string' ? JSON.parse(query) : query;
} catch (e) {
  return `Error: Invalid input format. Expected JSON. Got: ${query}`;
}

const { service, date, time, duration_minutes, client_name, client_phone, language } = input;
const lang = language || 'es';

if (!service || !date || !time || !duration_minutes || !client_name || !client_phone) {
  return 'Error: Missing required fields. Need: service, date, time, duration_minutes, client_name, client_phone, language.';
}

// Calculate end time
const [h, m] = time.split(':').map(Number);
const startMin = h * 60 + m;
const endMin = startMin + Number(duration_minutes);
const endH = Math.floor(endMin / 60).toString().padStart(2, '0');
const endM = (endMin % 60).toString().padStart(2, '0');
const endTime = `${endH}:${endM}`;

const startDateTime = `${date}T${time}:00-03:00`;
const endDateTime = `${date}T${endTime}:00-03:00`;

const calId = typeof $env !== 'undefined' ? ($env.GOOGLE_CALENDAR_ID || 'primary') : 'primary';
const token = typeof $env !== 'undefined' ? ($env.GOOGLE_CALENDAR_ACCESS_TOKEN || '') : '';

const eventBody = {
  summary: `${service} - ${client_name}`,
  description: `Client: ${client_name}\nPhone: ${client_phone}\nService: ${service}\nDuration: ${duration_minutes} minutes\nLanguage: ${lang}\n\nBooked via WhatsApp Bot\nAREA MOSA Hair Salon - Cordon, Montevideo, Uruguay`,
  location: 'Cordon, Montevideo, Uruguay',
  start: {
    dateTime: startDateTime,
    timeZone: 'America/Montevideo'
  },
  end: {
    dateTime: endDateTime,
    timeZone: 'America/Montevideo'
  },
  reminders: {
    useDefault: false,
    overrides: [
      { method: 'popup', minutes: 60 },
      { method: 'popup', minutes: 1440 }
    ]
  },
  colorId: '2'
};

try {
  const resp = await $helpers.httpRequest({
    method: 'POST',
    url: `https://www.googleapis.com/calendar/v3/calendars/${encodeURIComponent(calId)}/events`,
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    },
    body: eventBody
  });

  if (resp.id) {
    return `BOOKING CONFIRMED\nEvent ID: ${resp.id}\nService: ${service}\nDate: ${date}\nTime: ${time} - ${endTime} (${duration_minutes} min)\nClient: ${client_name}\nPhone: ${client_phone}\nLanguage: ${lang}\nSalon: AREA MOSA, Cordon, Montevideo, Uruguay`;
  } else {
    return `BOOKING ERROR: Unexpected response from calendar API: ${JSON.stringify(resp)}`;
  }
} catch (err) {
  return `BOOKING ERROR: Could not create calendar event. Error: ${err.message}. Please ask the client to contact the salon directly at +598 94 786877 to confirm the appointment manually.`;
}
